     6Ôćĺ		const now = new Date();
     7Ôćĺ		const sameDay =
     8Ôćĺ			date.getFullYear() === now.getFullYear() &&
     9Ôćĺ			date.getMonth() === now.getMonth() &&
    10Ôćĺ			date.getDate() === now.getDate();
    11Ôćĺ		if (sameDay) {
    12Ôćĺ			return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    13Ôćĺ		}
