            expect(times).toHaveLength(2);
        });
    });

    describe('chat switching', () => {
        it('updates to show the new chat partner name on selection change', async () => {
            render(Chat);
            await expect.element(page.getByText('Claudia')).toBeInTheDocument();
            appState.currentlySelected = 1;
