### 1. `src/lib/time.ts` (new)

```ts
/** Format a message time: HH:MM if today, else "Mon DD". */
export function formatTime(date: Date): string {
    const now = new Date();
    const sameDay =
        date.getFullYear() === now.getFullYear() &&
        date.getMonth() === now.getMonth() &&
        date.getDate() === now.getDate();
    if (sameDay) {
        return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    }
    return date.toLocaleDateString([], { month: 'short', day: 'numeric' });
}
```

Then in `Selector.svelte`: remove the inline definition, add `import { formatTime } from './time.js';`.

### 2. `src/lib/Chat.svelte` ÔÇö full component

**Script:**
```svelte
<script lang="ts">
    import { appState } from './state.svelte.js';
    import { formatTime } from './time.js';

    const chat = $derived(appState.chats[appState.currentlySelected]);

    let messagesEl: HTMLUListElement;

    // Scroll-lock: true = auto-follow new messages. Updated by the scroll listener
    // so we capture position before DOM changes, avoiding post-update timing issues.
    let scrollLocked = true;

    function onScroll() {
        if (!messagesEl) return;
        scrollLocked = messagesEl.scrollHeight - messagesEl.scrollTop - messagesEl.clientHeight < 16;
    }

    // Always start at the bottom when opening a different chat
    $effect(() => {
        appState.currentlySelected;
        scrollLocked = true;
    });

    // After each DOM update, scroll only if the user was already at the bottom
    $effect(() => {
        chat.messages.length;
        if (scrollLocked) messagesEl?.scrollTo({ top: messagesEl.scrollHeight });
    });
</script>
```

**Template** ÔÇö uses `data-*` for role/status and semantic elements (`<header>`, `<figure>`, `<time>`) to keep classes minimal:
```svelte
<section class="chat">
    <header>
        <figure>
            <img src={chat.profilePicture} alt={chat.name} />
            <span data-status={chat.status}></span>
        </figure>
        <div>
            <strong>{chat.name}</strong>
            <small>{chat.statusText}</small>
        </div>
    </header>

    {#if chat.messages.length === 0}
        <p class="empty">No messages yet. Say something.</p>
    {:else}
        <ul bind:this={messagesEl} onscroll={onScroll}>
            {#each chat.messages as msg, i (i)}
                <li data-role={msg.role}>
                    {#if msg.role === 'partner'}
                        <img src={chat.profilePicture} alt={chat.name} />
                    {/if}
                    <p>
                        {msg.text}
                        <time datetime={msg.time.toISOString()}>{formatTime(msg.time)}</time>
                    </p>
                </li>
            {/each}
        </ul>
    {/if}
</section>
```

**CSS** ÔÇö element + attribute selectors eliminate most class noise. Only `.chat` and `.empty` are classes:
```css
.chat { display: flex; flex-direction: column; }
/* parent handles flex:1; overflow-y:auto via :global(.chat) */

header {
    display: flex; align-items: center; gap: 8px;
    padding: 8px; border-bottom: 1px solid #ddd;
    background: white; position: sticky; top: 0;
}
header figure {
    position: relative; flex-shrink: 0; width: 40px; height: 40px; margin: 0;
}
header figure img {
    width: 40px; height: 40px; border-radius: 50%;
    object-fit: cover; background: #ccc;
}
header figure span {
    position: absolute; bottom: 1px; right: 1px;
    width: 10px; height: 10px; border-radius: 50%; border: 2px solid white;
}
/* Status colours via data attribute */
header figure span[data-status="active"]  { background: #4caf50; }
header figure span[data-status="away"]    { background: #ff9800; }
header figure span[data-status="busy"]    { background: #f44336; }
header figure span[data-status="offline"] { background: #9e9e9e; }
header strong { display: block; }
header small  { color: #555; }

ul { list-style: none; margin: 0; padding: 8px; display: flex; flex-direction: column; gap: 8px; }

li { display: flex; align-items: flex-end; gap: 6px; }
li[data-role="user"]    { justify-content: flex-end; }
li[data-role="partner"] { justify-content: flex-start; }

li img { width: 32px; height: 32px; border-radius: 50%; background: #ccc; flex-shrink: 0; }

li p {
    max-width: 60%; margin: 0; padding: 6px 10px; border-radius: 12px;
    word-break: break-word;
}
li[data-role="user"] p    { background: #0084ff; color: white; border-bottom-right-radius: 2px; }
li[data-role="partner"] p { background: #e9e9eb; border-bottom-left-radius: 2px; }

time { display: block; font-size: 0.7em; opacity: 0.65; }

.empty { color: #999; font-style: italic; text-align: center; padding: 16px; }
```

Net class count: **2** (`.chat` required by parent; `.empty` for the empty state) vs ~14 in the original draft.

